interface ButtonServiceProps extends ComponentPropsWithoutRef<"div"> {
  className?: string;
  icon: React.ComponentType<React.SVGProps<SVGSVGElement>>;
  title: string;
}

export const ButtonService: React.FC<ButtonServiceProps> = ({
  className,
  icon: Icon,
  title,
  ...props
}) => {
  return (
    <div className={`flex items-center gap-4 h-[128px] ${className}`} {...props}>
      <Icon className="" />
      <span className="text-lg">{title}</span>
    </div>
  );
};
